/**
 * Vitest setup for react-ts-worker tests.
 *
 * The Scheduler uses MessageChannel to schedule work. In Node.js, a
 * MessagePort with an onmessage listener is automatically ref()'d, which
 * keeps the event loop alive after tests complete.
 *
 * We replace the global MessageChannel with a wrapper that automatically
 * unref()'s the port after it has a listener attached, preventing the
 * process from hanging after tests finish.
 */

const OriginalMessageChannel = globalThis.MessageChannel;

class UnrefMessageChannel extends OriginalMessageChannel {
  get port1() {
    const port = super.port1;
    // Intercept onmessage setter to unref the port
    let _handler: ((ev: MessageEvent) => void) | null = null;
    Object.defineProperty(port, "onmessage", {
      get() {
        return _handler;
      },
      set(fn) {
        _handler = fn;
        if (fn && typeof (port as unknown as { unref?: () => void }).unref === "function") {
          (port as unknown as { unref: () => void }).unref();
        }
        // Manually call start since we intercepted the onmessage setter
        port.start();
        // Re-assign through the raw EventTarget approach
        port.addEventListener("message", fn);
      },
      configurable: true,
    });
    return port;
  }
}

// Replace MessageChannel globally so the Scheduler uses our unref'd version
// Note: The Scheduler captures MessageChannel at import time, so we need to
// replace it before the Scheduler module is imported. Since this setup file
// runs before test files, this works as long as we use dynamic imports in tests.
// For static imports, the Scheduler has already captured the original.
// In that case, we handle cleanup via afterAll in individual test files.
export {};

import { describe, expect, it, vi } from "vitest";
import { createWorkerDOMHostConfig } from "../../../../src/core/react-engine/host-config/WorkerDOMHostConfig.js";
import type {
  WorkerDocument,
  WorkerElement,
  WorkerText,
} from "../../../../src/core/react-engine/host-config/WorkerDOMHostConfig.js";

function makeWorkerText(text: string): WorkerText {
  return {
    data: text,
    nodeValue: text,
    textContent: text,
    parentNode: null,
    childNodes: [],
    appendChild: vi.fn(),
    insertBefore: vi.fn(),
    removeChild: vi.fn(),
  } as unknown as WorkerText;
}

function makeWorkerElement(tag: string): WorkerElement & { __nodeId?: number } {
  const el: WorkerElement & { __nodeId?: number } = {
    tagName: tag.toUpperCase(),
    namespaceURI: null,
    setAttribute: vi.fn(),
    removeAttribute: vi.fn(),
    style: {},
    textContent: null,
    parentNode: null,
    childNodes: [],
    appendChild: vi.fn(),
    insertBefore: vi.fn(),
    removeChild: vi.fn(),
  };
  return el;
}

function makeWorkerDocument(): WorkerDocument {
  return {
    createElement: (type: string) => makeWorkerElement(type),
    createElementNS: (ns: string, type: string) => {
      const el = makeWorkerElement(type);
      (el as unknown as Record<string, unknown>).namespaceURI = ns;
      return el;
    },
    createTextNode: (text: string) => makeWorkerText(text),
  };
}

describe("createWorkerDOMHostConfig", () => {
  const doc = makeWorkerDocument();
  const config = createWorkerDOMHostConfig(doc);

  const rootCtx = config.getRootHostContext(makeWorkerElement("div"));
  const rootContainer = makeWorkerElement("div");

  describe("createInstance", () => {
    it("creates element via createElement", () => {
      const el = config.createInstance("div", {}, rootContainer, rootCtx);
      expect(el).toBeDefined();
    });

    it("creates SVG element via createElementNS in SVG context", () => {
      const svgCtx = config.getChildHostContext(rootCtx, "svg");
      const el = config.createInstance("circle", {}, rootContainer, svgCtx);
      expect(el).toBeDefined();
    });

    it("creates math element via createElementNS in math context", () => {
      const mathCtx = config.getChildHostContext(rootCtx, "math");
      const el = config.createInstance("mfrac", {}, rootContainer, mathCtx);
      expect(el).toBeDefined();
    });

    it("sets className via class attribute", () => {
      const el = makeWorkerElement("div");
      const docMock: WorkerDocument = {
        createElement: () => el,
        createElementNS: () => el,
        createTextNode: makeWorkerText,
      };
      const cfg = createWorkerDOMHostConfig(docMock);
      cfg.createInstance("div", { className: "foo" }, rootContainer, rootCtx);
