// Middleware
// ---------------------------------------------------------------------------

describe("middleware", () => {
  it("creates a middleware with fn property", () => {
    const mw = middleware<{}, { userId: string }>(async ({ ctx, next }) =>
      next({ ...ctx, userId: "user-123" }),
    );
    expect(typeof mw.fn).toBe("function");
  });

  it("middleware can be used in a procedure chain", async () => {
    const withUserId = middleware<{}, { userId: string }>(async ({ ctx, next }) =>
      next({ ...ctx, userId: "user-123" }),
    );

    const t = createProcedure().use(withUserId);

    const tool = t
      .tool("user_tool", "Uses user id", { name: z.string() })
      .handler(async ({ input, ctx }) => ({
        content: [{ type: "text", text: `${input.name} by ${ctx.userId}` }],
      }));

    const result = await tool.handler({ name: "Alice" }, {});
    expect(result.content[0]!.text).toBe("Alice by user-123");
  });

  it("middleware receives input and context", async () => {
    const capturedParams: { input: unknown; ctx: unknown }[] = [];

    const captureMw = middleware<{}, {}>(async ({ input, ctx, next }) => {
      capturedParams.push({ input, ctx });
      return next(ctx);
    });

    const tool = createProcedure()
      .use(captureMw)
      .tool("capture_tool", "Captures params", { value: z.number() })
      .handler(async ({ input }) => ({
        content: [{ type: "text", text: String(input.value) }],
      }));

    await tool.handler({ value: 42 }, { existingKey: "hello" });
    expect(capturedParams).toHaveLength(1);
    expect(capturedParams[0]!.input).toEqual({ value: 42 });
    expect(capturedParams[0]!.ctx).toEqual({ existingKey: "hello" });
  });

  it("multiple middleware compose correctly", async () => {
    const steps: string[] = [];

    const mw1 = middleware<{}, { step1: boolean }>(async ({ ctx, next }) => {
      steps.push("mw1-before");
      const result = await next({ ...ctx, step1: true });
      steps.push("mw1-after");
      return result;
    });

    const mw2 = middleware<{ step1: boolean }, { step1: boolean; step2: boolean }>(
      async ({ ctx, next }) => {
        steps.push("mw2-before");
        const result = await next({ ...ctx, step2: true });
        steps.push("mw2-after");
        return result;
      },
    );

    const tool = createProcedure()
      .use(mw1)
      .use(mw2)
      .tool("multi_mw_tool", "Multi middleware", { x: z.string() })
      .handler(async ({ ctx }) => {
        steps.push("handler");
        expect((ctx as { step1: boolean; step2: boolean }).step1).toBe(true);
        expect((ctx as { step1: boolean; step2: boolean }).step2).toBe(true);
        return { content: [{ type: "text", text: "done" }] };
      });

    await tool.handler({ x: "test" }, {});
    expect(steps).toEqual(["mw1-before", "mw2-before", "handler", "mw2-after", "mw1-after"]);
  });

  it("middleware can short-circuit the chain", async () => {
    const authMw = middleware<{}, { authorized: boolean }>(async () => {
      // Don't call next — return error immediately
      return {
        content: [{ type: "text", text: "Unauthorized" }],
        isError: true,
      };
    });

    const handlerCalled = { value: false };
    const tool = createProcedure()
      .use(authMw)
      .tool("auth_tool", "Auth required", { x: z.string() })
      .handler(async () => {
        handlerCalled.value = true;
        return { content: [{ type: "text", text: "secret" }] };
      });

    const result = await tool.handler({ x: "test" }, {});
    expect(result.isError).toBe(true);
    expect(result.content[0]!.text).toBe("Unauthorized");
    expect(handlerCalled.value).toBe(false);
  });

  it("handler receives initial ctx when no middleware", async () => {
    const tool = baseProcedure
      .tool("ctx_tool", "Gets ctx", { x: z.string() })
      .handler(async ({ ctx }) => ({
        content: [{ type: "text", text: JSON.stringify(ctx) }],
      }));

    const result = await tool.handler({ x: "test" }, { myKey: "myValue" });
    expect(result.content[0]!.text).toContain("myValue");
  });

  it("handler receives empty object ctx when ctx arg omitted", async () => {
    const tool = baseProcedure
      .tool("no_ctx_tool", "No ctx arg", { x: z.string() })
      .handler(async ({ ctx }) => ({
        content: [{ type: "text", text: JSON.stringify(ctx) }],
      }));

    const result = await tool.handler({ x: "test" });
    expect(result.content[0]!.text).toBe("{}");
  });
});

import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";

// We test the module-level functions by importing the hook and exercising the
// exported API. We need to mock React hooks and TanStack Router.

// Mock useRouter to provide a subscribe function
const mockUnsubscribe = vi.fn();
const mockSubscribe = vi.fn().mockReturnValue(mockUnsubscribe);
vi.mock("@tanstack/react-router", () => ({
  useRouter: () => ({
    subscribe: mockSubscribe,
  }),
}));

// Mock React hooks
vi.mock("react", async () => {
  const actual = await vi.importActual<typeof import("react")>("react");
  return {
    ...actual,
    useCallback: (fn: Function) => fn,
    useEffect: (fn: Function) => {
      fn();
    },
    useRef: (val: unknown) => ({ current: val }),
  };
});

describe("useAnalytics", () => {
  let mockFetch: ReturnType<typeof vi.fn>;
  let mockSendBeacon: ReturnType<typeof vi.fn>;

  beforeEach(async () => {
    mockFetch = vi.fn().mockResolvedValue({ status: 200 } as Response);
    vi.stubGlobal("fetch", mockFetch);

    mockSendBeacon = vi.fn().mockReturnValue(true);
    vi.stubGlobal("navigator", {
      sendBeacon: mockSendBeacon,
      userAgent: "test-agent",
    });

    // Reset module state between tests
    vi.resetModules();
    mockSubscribe.mockClear();
    mockUnsubscribe.mockClear();
  });

  afterEach(() => {
    vi.unstubAllGlobals();
    vi.useRealTimers();
  });

  it("flushEvents POSTs to /api/analytics/ingest with correct format", async () => {
    vi.useFakeTimers();

    const { useAnalytics } = await import("@/ui/hooks/useAnalytics");
    const analytics = useAnalytics();

    analytics.trackCustomEvent("test_event", { key: "value" });

    // Trigger flush via timer
    vi.advanceTimersByTime(31000);

    expect(mockFetch).toHaveBeenCalledWith(
      "/analytics/ingest",
      expect.objectContaining({
        method: "POST",
        headers: { "Content-Type": "application/json" },
        keepalive: true,
      }),
    );

    const body = JSON.parse(mockFetch.mock.calls[0]![1].body);
    expect(Array.isArray(body)).toBe(true);
    expect(body[0].source).toBe("spike-app");
    expect(body[0].eventType).toBe("test_event");
    expect(body[0].metadata.key).toBe("value");
  });

  it("uses sendBeacon when document is hidden", async () => {
    vi.useFakeTimers();

    // Set document as hidden
    Object.defineProperty(document, "visibilityState", {
      value: "hidden",
      writable: true,
      configurable: true,
    });

    const { useAnalytics } = await import("@/ui/hooks/useAnalytics");
    const analytics = useAnalytics();

    analytics.trackEvent("beacon_test", { page: "/test" });

    // Trigger flush
    vi.advanceTimersByTime(31000);

    expect(mockSendBeacon).toHaveBeenCalledWith("/analytics/ingest", expect.any(Blob));

    // Restore
    Object.defineProperty(document, "visibilityState", {
      value: "visible",
      writable: true,
      configurable: true,
    });
  });

  it("handles 429 response with backoff", async () => {
    vi.useFakeTimers();

    mockFetch.mockResolvedValue({ status: 429 } as Response);

    const { useAnalytics } = await import("@/ui/hooks/useAnalytics");
    const analytics = useAnalytics();

    analytics.trackEvent("test", {});
    vi.advanceTimersByTime(31000);

    // After 429, the interval should increase to 30s (backoff)
    // Enqueue another event
    await vi.advanceTimersByTimeAsync(100); // let the fetch promise resolve

    mockFetch.mockClear();
    analytics.trackEvent("test2", {});

    // Normal interval (5s) should NOT flush yet due to backoff
    vi.advanceTimersByTime(31000);
    // The backoff may or may not have taken effect depending on async timing,
    // but the module should not throw
  });

  it("clears queue after flush", async () => {
    vi.useFakeTimers();

    const { useAnalytics } = await import("@/ui/hooks/useAnalytics");
    const analytics = useAnalytics();

    analytics.trackEvent("event1", {});
    vi.advanceTimersByTime(31000);

    expect(mockFetch).toHaveBeenCalledTimes(1);

    mockFetch.mockClear();

    // Without new events, another timer cycle should not flush
    vi.advanceTimersByTime(31000);
    expect(mockFetch).not.toHaveBeenCalled();
  });

  it("auto-tracks page views on route change via subscribe", async () => {
    vi.useFakeTimers();

    const { useAnalytics: _useAnalytics } = await import("@/ui/hooks/useAnalytics");
    _useAnalytics();

    // useEffect should have called router.subscribe("onResolved", ...)
    expect(mockSubscribe).toHaveBeenCalledWith("onResolved", expect.any(Function));

    // Simulate a route change
    const onResolved = mockSubscribe.mock.calls[0]![1];
    onResolved({ toLocation: { pathname: "/dashboard" } });

    // Flush the queued page_view event
    vi.advanceTimersByTime(31000);

    expect(mockFetch).toHaveBeenCalled();
    const body = JSON.parse(mockFetch.mock.calls[0]![1].body);
    expect(body[0].eventType).toBe("page_view");
    expect(body[0].metadata.path).toBe("/dashboard");
  });

  it("flushes events with correct source and eventType structure", async () => {
    vi.useFakeTimers();

    const { useAnalytics } = await import("@/ui/hooks/useAnalytics");
    const analytics = useAnalytics();

    analytics.trackEvent("custom_test", { key1: "val1", key2: 42 });
    vi.advanceTimersByTime(31000);

    expect(mockFetch).toHaveBeenCalled();
    const body = JSON.parse(mockFetch.mock.calls[0]![1].body);
    expect(Array.isArray(body)).toBe(true);
    expect(body[0].source).toBe("spike-app");
    expect(body[0].eventType).toBe("custom_test");
    expect(body[0].metadata.key1).toBe("val1");
    expect(body[0].metadata.key2).toBe(42);
  });
});

import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { program } from "commander";
import * as auth from "../../src/cli/spike-cli/core-logic/commands/auth.js";
import * as alias from "../../src/cli/spike-cli/core-logic/commands/alias.js";
import { main } from "../../src/cli/spike-cli/core-logic/cli.js";

// Mock the commands so we don't trigger real logic
vi.mock("../../src/cli/spike-cli/core-logic/commands/auth", () => ({
  registerAuthCommand: vi.fn(),
}));
vi.mock("../../src/cli/spike-cli/core-logic/commands/alias", () => ({
  registerAliasCommand: vi.fn(),
}));
vi.mock("../../src/cli/spike-cli/core-logic/commands/completions", () => ({
  registerCompletionsCommand: vi.fn(),
}));
vi.mock("../../src/cli/spike-cli/core-logic/commands/registry", () => ({
  registerRegistryCommand: vi.fn(),
}));
vi.mock("../../src/cli/spike-cli/ai-cli/agent", () => ({ registerAgentCommand: vi.fn() }));
vi.mock("../../src/cli/spike-cli/node-sys/store", () => ({
  loadAliases: vi.fn().mockResolvedValue({ commands: {} }),
}));

describe("cli", () => {
  const originalArgv = process.argv;

  beforeEach(() => {
    vi.clearAllMocks();
    vi.spyOn(console, "log").mockImplementation(() => {});
    // Reset program state
    // @ts-expect-error - reaching into commander internals
    program.commands = [];
    // @ts-expect-error - reaching into commander internals
    program.options = [];
    vi.spyOn(program, "parse").mockImplementation(() => program as unknown as typeof program);
  });

  afterEach(() => {
    process.argv = originalArgv;
  });

  it("registers all commands", async () => {
    process.argv = ["node", "spike"];
    await main();

    expect(auth.registerAuthCommand).toHaveBeenCalled();
    expect(alias.registerAliasCommand).toHaveBeenCalled();
  });

  it("handles --generate-completions", async () => {
    process.argv = ["node", "spike", "--generate-completions"];
    await main();

    expect(console.log).toHaveBeenCalledWith("auth");
    expect(console.log).toHaveBeenCalledWith("--verbose");
    // Should NOT have called parse because it exits early
    expect(program.parse).not.toHaveBeenCalled();
  });

  it("rewrites command aliases", async () => {
    const store = await import("../../src/cli/spike-cli/node-sys/store");
    vi.mocked(store.loadAliases).mockResolvedValue({
      commands: { st: "status" },
    } as unknown as { commands: Record<string, string> });

    process.argv = ["node", "spike", "st"];
    await main();

    expect(process.argv[2]).toBe("status");
  });

  it("preAction hook sets verbose when --verbose is passed", async () => {
    const logger = await import("../../src/cli/spike-cli/core-logic/util/logger");
    const setVerboseSpy = vi.spyOn(logger, "setVerbose");

    // Restore real parse to let the preAction hook fire
    vi.mocked(program.parse).mockRestore?.();
    vi.spyOn(program, "parse").mockImplementation((argv, opts) => {
      // Manually invoke preAction by simulating what commander does:
      // walk hooks and call preAction with a command that has verbose=true
      const hooks = (program as Record<string, unknown>)._lifeCycleHooks as
        | Record<string, Array<(cmd: unknown) => void>>
        | undefined;
      if (hooks?.["preAction"]) {
        for (const hook of hooks["preAction"]) {
          hook(
            Object.assign(Object.create(program), {
              opts: () => ({ verbose: true }),
            }),
          );
        }
      }
      return program as unknown as typeof program;
    });

    process.argv = ["node", "spike", "--verbose", "auth"];
    await main();

    expect(setVerboseSpy).toHaveBeenCalledWith(true);
    // cleanup
    logger.setVerbose(false);
  });

  it("handles alias loading failure silently", async () => {
    const store = await import("../../src/cli/spike-cli/node-sys/store");
    vi.mocked(store.loadAliases).mockRejectedValue(new Error("load failed"));

    process.argv = ["node", "spike", "status"];
    // Should not throw
    await main();
    expect(process.argv[2]).toBe("status");
  });

  it("handles non-alias command", async () => {
    const store = await import("../../src/cli/spike-cli/node-sys/store");
    vi.mocked(store.loadAliases).mockResolvedValue({
      commands: { st: "status" },
    } as any);

    process.argv = ["node", "spike", "not-an-alias"];
    await main();
    expect(process.argv[2]).toBe("not-an-alias");
  });

  it("preAction hook does not set verbose when --verbose is missing", async () => {
    const logger = await import("../../src/cli/spike-cli/core-logic/util/logger");
    const setVerboseSpy = vi.spyOn(logger, "setVerbose");

    vi.spyOn(program, "parse").mockImplementation(() => {
      const hooks = (program as any)._lifeCycleHooks;
      if (hooks?.["preAction"]) {
        for (const hook of hooks["preAction"]) {
          hook({ opts: () => ({ verbose: false }) });
        }
      }
      return program;
    });

    process.argv = ["node", "spike", "status"];
    await main();

    expect(setVerboseSpy).not.toHaveBeenCalledWith(true);
  });
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import { Command } from "commander";
import { registerAuthCommand } from "../../../src/cli/spike-cli/core-logic/commands/auth";
import * as flow from "../../../src/cli/spike-cli/node-sys/device-flow";
import * as store from "../../../src/cli/spike-cli/node-sys/token-store";
import type { AuthTokens } from "../../../src/cli/spike-cli/node-sys/token-store";

vi.mock("../../../src/cli/spike-cli/node-sys/device-flow", () => ({ deviceCodeLogin: vi.fn() }));
vi.mock("../../../src/cli/spike-cli/node-sys/token-store", () => ({
  deleteTokens: vi.fn(),
  loadTokens: vi.fn(),
  isTokenExpired: vi.fn(),
}));
vi.mock("../../../src/cli/spike-cli/core-logic/onboarding/wizard", () => ({
  runOnboardingWizard: vi.fn().mockRejectedValue(new Error("skip")),
  submitOnboarding: vi.fn(),
}));

describe("auth command", () => {
  let program: Command;

  beforeEach(() => {
    program = new Command();
    vi.clearAllMocks();
    vi.spyOn(console, "error").mockImplementation(() => {});
  });

  it("registers auth commands", () => {
    registerAuthCommand(program);
    const auth = program.commands.find((c) => c.name() === "auth")!;
    expect(auth).toBeDefined();
    expect(auth.commands.find((c) => c.name() === "login")).toBeDefined();
    expect(auth.commands.find((c) => c.name() === "logout")).toBeDefined();
    expect(auth.commands.find((c) => c.name() === "status")).toBeDefined();
  });

  it("login handles successful device flow", async () => {
    vi.mocked(flow.deviceCodeLogin).mockResolvedValue({
      accessToken: "abc",
      baseUrl: "https://test",
    } as unknown as AuthTokens);

    registerAuthCommand(program);
    const login = program.commands[0].commands.find((c) => c.name() === "login")!;
    // @ts-expect-error - accessing private commander handler
    await login._actionHandler([{ baseUrl: "https://test" }, []]);

    expect(flow.deviceCodeLogin).toHaveBeenCalled();
    expect(console.error).toHaveBeenCalledWith(expect.stringContaining("Logged in successfully"));
  });

  it("logout deletes tokens", async () => {
    registerAuthCommand(program);
    const logout = program.commands[0].commands.find((c) => c.name() === "logout")!;
    // @ts-expect-error - accessing private commander handler
    await logout._actionHandler([{}, []]);
    expect(store.deleteTokens).toHaveBeenCalled();
  });

  it("status shows login info", async () => {
    vi.mocked(store.loadTokens).mockResolvedValue({
      baseUrl: "https://test",
    } as unknown as AuthTokens);
    vi.mocked(store.isTokenExpired).mockReturnValue(false);

    registerAuthCommand(program);
    const status = program.commands[0].commands.find((c) => c.name() === "status")!;
    // @ts-expect-error - accessing private commander handler
    await status._actionHandler([{}, []]);

    expect(console.error).toHaveBeenCalledWith(
      expect.stringContaining("Logged in to: https://test"),
    );
  });

  it("status handles not logged in", async () => {
    vi.mocked(store.loadTokens).mockResolvedValue(null);
    registerAuthCommand(program);
    const status = program.commands[0].commands.find((c) => c.name() === "status")!;
    // @ts-expect-error - accessing private commander handler
    await status._actionHandler([{}, []]);
    expect(console.error).toHaveBeenCalledWith(expect.stringContaining("Not logged in"));
  });

  it("login handles onboarding skip", async () => {
    vi.mocked(flow.deviceCodeLogin).mockResolvedValue({
      accessToken: "abc",
      baseUrl: "https://test",
    } as unknown as AuthTokens);
    const wizard = await import("../../../src/cli/spike-cli/core-logic/onboarding/wizard");
    vi.mocked(wizard.runOnboardingWizard).mockRejectedValue(new Error("skip"));

    registerAuthCommand(program);
    const login = program.commands[0].commands.find((c) => c.name() === "login")!;
    // @ts-expect-error - accessing private commander handler
    await login._actionHandler([{ baseUrl: "https://test" }, []]);

    expect(console.error).toHaveBeenCalledWith(expect.stringContaining("Logged in successfully"));
  });

  it("login triggers onUserCode callback", async () => {
    vi.mocked(flow.deviceCodeLogin).mockImplementation(async (options) => {
      options.onUserCode?.("USER-CODE", "https://spike.land/activate");
      return { accessToken: "abc", baseUrl: "https://test" } as unknown as AuthTokens;
    });

    registerAuthCommand(program);
    const login = program.commands[0].commands.find((c) => c.name() === "login")!;
    // @ts-expect-error
    await login._actionHandler([{ baseUrl: "https://test" }, []]);

    expect(console.error).toHaveBeenCalledWith(
      expect.stringContaining("https://spike.land/activate"),
    );
    expect(console.error).toHaveBeenCalledWith(expect.stringContaining("USER-CODE"));
  });

  it("login completes onboarding successfully", async () => {
    vi.mocked(flow.deviceCodeLogin).mockResolvedValue({
      accessToken: "abc",
      baseUrl: "https://test",
    } as unknown as AuthTokens);
    const wizard = await import("../../../src/cli/spike-cli/core-logic/onboarding/wizard");
    vi.mocked(wizard.runOnboardingWizard).mockResolvedValue({
      personaName: "Coder",
      personaId: 1,
      personaSlug: "coder",
      answers: [true],
    });
    vi.mocked(wizard.submitOnboarding).mockResolvedValue(undefined);

    registerAuthCommand(program);
    const login = program.commands[0].commands.find((c) => c.name() === "login")!;
    // @ts-expect-error
    await login._actionHandler([{ baseUrl: "https://test" }, []]);

    expect(console.error).toHaveBeenCalledWith(expect.stringContaining("Welcome"));
  });

  it("status shows expiry info when expiresAt is set", async () => {
    vi.mocked(store.loadTokens).mockResolvedValue({
      baseUrl: "https://test",
      expiresAt: "2030-01-01T00:00:00Z",
    } as unknown as AuthTokens);
    vi.mocked(store.isTokenExpired).mockReturnValue(false);

    registerAuthCommand(program);
    const status = program.commands[0].commands.find((c) => c.name() === "status")!;
    // @ts-expect-error
    await status._actionHandler([{}, []]);

    expect(console.error).toHaveBeenCalledWith(expect.stringContaining("Expires at:"));
  });
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import { Hono } from "hono";
import type { Env } from "../../../src/edge-api/main/core-logic/env.js";
import { blogComments } from "../../../src/edge-api/main/api/routes/blog-comments.js";
import { clearEloCache } from "../../../src/edge-api/main/core-logic/elo-service.js";

const AUTH_COOKIE = "session=valid-session";

/**
 * blogComments routes use authMiddleware inline on POST/DELETE/vote endpoints.
 * To pass auth we mock AUTH_MCP to return a valid session for the given userId.
 */
function createMockEnv(
  dbFirstImpl?: () => Promise<unknown>,
  dbAllImpl?: () => Promise<unknown>,
  batchImpl?: () => Promise<unknown>,
  userId = "user1",
): Env {
  const prepareMock = vi.fn().mockReturnValue({
    bind: vi.fn().mockReturnThis(),
    first: dbFirstImpl ? vi.fn().mockImplementation(dbFirstImpl) : vi.fn().mockResolvedValue(null),
    all: dbAllImpl
      ? vi.fn().mockImplementation(dbAllImpl)
      : vi.fn().mockResolvedValue({ results: [] }),
    run: vi.fn().mockResolvedValue({}),
  });

  return {
    DB: {
      prepare: prepareMock,
      batch: batchImpl ? vi.fn().mockImplementation(batchImpl) : vi.fn().mockResolvedValue([]),
    } as unknown as D1Database,
    AUTH_MCP: {
      fetch: vi.fn().mockResolvedValue(
        new Response(JSON.stringify({ session: { id: "sess1" }, user: { id: userId } }), {
          status: 200,
        }),
      ),
    } as unknown as Fetcher,
    INTERNAL_SERVICE_SECRET: "internal-secret-123",
  } as unknown as Env;
}

function makeApp() {
  const app = new Hono<{ Bindings: Env }>();
  app.route("/", blogComments);
  return app;
}

describe("blogComments — GET /blog/:slug/comments", () => {
  it("returns list of comments", async () => {
    const env = createMockEnv(undefined, () =>
      Promise.resolve({ results: [{ id: "c1", content: "Great post!" }] }),
    );
    const app = makeApp();
    const res = await app.request("/blog/my-post/comments", {}, env);
    expect(res.status).toBe(200);
    const body = await res.json<Array<{ id: string }>>();
    expect(body[0].id).toBe("c1");
  });

  it("returns empty array when no comments", async () => {
    const env = createMockEnv();
    const app = makeApp();
    const res = await app.request("/blog/no-comments-post/comments", {}, env);
    expect(res.status).toBe(200);
    const body = await res.json<unknown[]>();
    expect(body).toEqual([]);
  });
});

describe("blogComments — POST /blog/:slug/comments", () => {
  it("returns 400 when content or user_name missing", async () => {
    const env = createMockEnv();
    const app = makeApp();
    const res = await app.request(
      "/blog/my-post/comments",
      {
        method: "POST",
        body: JSON.stringify({ content: "", user_name: "Alice" }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(400);
    const body = await res.json<{ error: string }>();
    expect(body.error).toContain("required");
  });

  it("returns 400 when comment too long", async () => {
    const env = createMockEnv();
    const app = makeApp();
    const res = await app.request(
      "/blog/my-post/comments",
      {
        method: "POST",
        body: JSON.stringify({ content: "a".repeat(5001), user_name: "Alice" }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(400);
    const body = await res.json<{ error: string }>();
    expect(body.error).toContain("too long");
  });

  it("returns 404 when parent comment not found", async () => {
    const env = createMockEnv(() => Promise.resolve(null));
    const app = makeApp();
    const res = await app.request(
      "/blog/my-post/comments",
      {
        method: "POST",
        body: JSON.stringify({ content: "Reply", user_name: "Alice", parent_id: "nonexistent" }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(404);
  });

  it("creates comment successfully", async () => {
    const firstMock = vi.fn().mockResolvedValue({ id: "c-new", created_at: Date.now() });
    const env = createMockEnv(() => firstMock());
    const app = makeApp();
    const res = await app.request(
      "/blog/my-post/comments",
      {
        method: "POST",
        body: JSON.stringify({ content: "Nice post!", user_name: "Alice" }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(201);
  });

  it("creates reply when parent exists", async () => {
    let callCount = 0;
    const env = createMockEnv(() => {
      callCount++;
      if (callCount === 1) return Promise.resolve({ id: "parent-id" });
      return Promise.resolve({ id: "c-reply", created_at: Date.now() });
    });
    const app = makeApp();
    const res = await app.request(
      "/blog/my-post/comments",
      {
        method: "POST",
        body: JSON.stringify({ content: "I agree!", user_name: "Bob", parent_id: "parent-id" }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(201);
  });
});

describe("blogComments — POST /blog/comments/:commentId/vote", () => {
  it("returns 400 for invalid vote value", async () => {
    const env = createMockEnv();
    const app = makeApp();
    const res = await app.request(
      "/blog/comments/c1/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: 0 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(400);
  });

  it("returns 404 when comment not found", async () => {
    const env = createMockEnv(() => Promise.resolve(null));
    const app = makeApp();
    const res = await app.request(
      "/blog/comments/nonexistent/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: 1 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(404);
  });

  it("returns 403 when user votes on own comment", async () => {
    const env = createMockEnv(() => Promise.resolve({ id: "c1", user_id: "user1", score: 0 }));
    const app = makeApp();
    const res = await app.request(
      "/blog/comments/c1/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: 1 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(403);
  });

  it("returns 409 when already voted same direction", async () => {
    let callCount = 0;
    const env = createMockEnv(() => {
      callCount++;
      if (callCount === 1) return Promise.resolve({ id: "c1", user_id: "other-user", score: 5 });
      if (callCount === 2) return Promise.resolve({ id: "v1", vote: 1 });
      return Promise.resolve({ score: 5 });
    });
    const app = makeApp();
    const res = await app.request(
      "/blog/comments/c1/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: 1 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(409);
  });

  it("changes vote direction when already voted opposite", async () => {
    let callCount = 0;
    const env = createMockEnv(() => {
      callCount++;
      if (callCount === 1) return Promise.resolve({ id: "c1", user_id: "other-user", score: 2 });
      if (callCount === 2) return Promise.resolve({ id: "v1", vote: -1 });
      return Promise.resolve({ score: 4 });
    });
    const app = makeApp();
    const res = await app.request(
      "/blog/comments/c1/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: 1 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(200);
  });

  it("adds new upvote", async () => {
    let callCount = 0;
    const env = createMockEnv(() => {
      callCount++;
      if (callCount === 1) return Promise.resolve({ id: "c1", user_id: "other-user", score: 3 });
      if (callCount === 2) return Promise.resolve(null);
      return Promise.resolve({ score: 4 });
    });
    const app = makeApp();
    const res = await app.request(
      "/blog/comments/c1/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: 1 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
      },
      env,
    );
    expect(res.status).toBe(200);
    const body = await res.json<{ score: number }>();
    expect(body.score).toBe(4);
  });

  it("applies ELO penalty when comment crosses downvote threshold", async () => {
    beforeEach(() => clearEloCache());
    let callCount = 0;
    const batchMock = vi.fn().mockResolvedValue([]);

    const prepareMock = vi.fn().mockImplementation((sql: string) => {
      const localCount = 0;
      return {
        bind: vi.fn().mockReturnThis(),
        first: vi.fn().mockImplementation(() => {
          callCount++;
          if (callCount === 1)
            return Promise.resolve({ id: "c1", user_id: "other-user", score: -9 });
          if (callCount === 2) return Promise.resolve(null); // no existing vote
          if (callCount === 3) return Promise.resolve({ score: -10 }); // crossed threshold
          // user_elo for ELO penalty
          return Promise.resolve({
            user_id: "other-user",
            elo: 1200,
            event_count: 0,
            daily_gains: 0,
            daily_reset_at: Date.now(),
            tier: "pro",
          });
        }),
        all: vi.fn().mockResolvedValue({ results: [] }),
        run: vi.fn().mockResolvedValue({}),
      };
    });

    const env: Env = {
      DB: { prepare: prepareMock, batch: batchMock } as unknown as D1Database,
      AUTH_MCP: {
        fetch: vi.fn().mockResolvedValue(
          new Response(JSON.stringify({ session: { id: "sess1" }, user: { id: "user1" } }), {
            status: 200,
          }),
        ),
      } as unknown as Fetcher,
      INTERNAL_SERVICE_SECRET: "internal-secret-123",
    } as unknown as Env;

    const app = makeApp();
    const res = await app.request(
      "/blog/comments/c1/vote",
      {
        method: "POST",
        body: JSON.stringify({ vote: -1 }),
        headers: { "Content-Type": "application/json", cookie: AUTH_COOKIE },
